  1→import { createWall } from '@/domain/models';
  2→import { distance } from '@/geometry/point';
  3→import { SNAP_DISTANCE_PX, MIN_WALL_LENGTH } from '@/domain/defaults';
  4→
  5→function snapToEndpoints(modelPos, walls, snapDistModel, chainStart) {
  6→  let best = null;
  7→  let bestDist = snapDistModel;
  8→
  9→  // Snap to chain start to close loop
 10→  if (chainStart) {
 11→    const d = distance(modelPos, chainStart);
 12→    if (d < bestDist) {
 13→      best = chainStart;
 14→      bestDist = d;
 15→    }
 16→  }
 17→
 18→  for (const wall of walls) {
 19→    for (const pt of [wall.start, wall.end]) {
 20→      const d = distance(modelPos, pt);
 21→      if (d < bestDist) {
 22→        best = pt;
 23→        bestDist = d;
 24→      }
 25→    }
 26→  }
 27→  return best;
 28→}
 29→
 30→function constrainAngle(start, end, shiftHeld) {
 31→  if (!shiftHeld) return end;
 32→  const dx = end.x - start.x;
 33→  const dy = end.y - start.y;
 34→  const angle = Math.atan2(dy, dx);
 35→  const snapAngle = Math.round(angle / (Math.PI / 4)) * (Math.PI / 4);
 36→  const len = Math.sqrt(dx * dx + dy * dy);
 37→  return {
 38→    x: start.x + Math.cos(snapAngle) * len,
 39→    y: start.y + Math.sin(snapAngle) * len,
 40→  };
 41→}
 42→
 43→export function createWallDrawHandler({ dispatch, editorDispatch, getFloor, activeFloorId, viewport, snapEnabled }) {
 44→  return {
 45→    onMouseDown(modelPos, e, toolState) {
 46→      if (e.button !== 0) return;
 47→
 48→      const floor = getFloor(activeFloorId);
 49→      const snapDistModel = SNAP_DISTANCE_PX / viewport.zoom;
 50→      const shiftHeld = e.shiftKey;
 51→
 52→      let snapped = modelPos;
 53→      if (snapEnabled) {
 54→        const snapPt = snapToEndpoints(modelPos, floor.walls, snapDistModel, toolState.chainStart);
 55→        if (snapPt) snapped = { ...snapPt };
 56→      }
 57→      if (shiftHeld && toolState.start) {
 58→        snapped = constrainAngle(toolState.start, snapped, true);
 59→      }
 60→
 61→      if (!toolState.start) {
 62→        // First click: set start
 63→        editorDispatch({
 64→          type: 'UPDATE_TOOL_STATE',
 65→          payload: { start: snapped, chainStart: snapped, preview: null },
 66→        });
 67→      } else {
 68→        // Second+ click: create wall and chain
 69→        const endPt = snapped;
 70→
 71→        const len = distance(toolState.start, endPt);
 72→        if (len < MIN_WALL_LENGTH) return;
 73→
 74→        const wall = createWall(toolState.start, endPt);
 75→        dispatch({ type: 'WALL_ADD', floorId: activeFloorId, wall });
 76→
 77→        // Check if we snapped back to chain start (close loop)
 78→        if (toolState.chainStart && distance(endPt, toolState.chainStart) < snapDistModel) {
 79→          editorDispatch({
 80→            type: 'UPDATE_TOOL_STATE',
 81→            payload: { start: null, chainStart: null, preview: null },
 82→          });
 83→        } else {
 84→          // Chain: end becomes new start
 85→          editorDispatch({
 86→            type: 'UPDATE_TOOL_STATE',
 87→            payload: { start: endPt, preview: null },
 88→          });
 89→        }
 90→      }
 91→    },
 92→
 93→    onMouseMove(modelPos, e, toolState) {
 94→      if (!toolState.start) return;
 95→      let preview = modelPos;
 96→
 97→      const floor = getFloor(activeFloorId);
 98→      const snapDistModel = SNAP_DISTANCE_PX / viewport.zoom;
 99→      if (snapEnabled) {
100→        const snapPt = snapToEndpoints(modelPos, floor.walls, snapDistModel, toolState.chainStart);
101→        if (snapPt) preview = { ...snapPt };
102→      }
103→      if (e.shiftKey) {
104→        preview = constrainAngle(toolState.start, preview, true);
105→      }
106→
107→      editorDispatch({
108→        type: 'UPDATE_TOOL_STATE',
109→        payload: { preview },
110→      });
111→    },
112→
113→    onDoubleClick(modelPos, e, toolState) {
114→      // Finish chain
115→      editorDispatch({
116→        type: 'UPDATE_TOOL_STATE',
117→        payload: { start: null, chainStart: null, preview: null },
118→      });
119→    },
120→
121→    onKeyDown(e, toolState) {
122→      if (e.key === 'Escape') {
123→        editorDispatch({
124→          type: 'UPDATE_TOOL_STATE',
125→          payload: { start: null, chainStart: null, preview: null },
126→        });
127→      }
128→    },
129→
130→    getCursor(toolState) {
131→      return 'crosshair';
132→    },
133→  };
134→}
