 1→import { subtract, dot, add, scale, distance } from './point';
 2→
 3→export function nearestPointOnSegment(p, a, b) {
 4→  const ab = subtract(b, a);
 5→  const ap = subtract(p, a);
 6→  const lenSq = dot(ab, ab);
 7→  if (lenSq === 0) return { point: { ...a }, t: 0 };
 8→  let t = dot(ap, ab) / lenSq;
 9→  t = Math.max(0, Math.min(1, t));
10→  return {
11→    point: add(a, scale(ab, t)),
12→    t,
13→  };
14→}
15→
16→export function distanceToSegment(p, a, b) {
17→  const { point } = nearestPointOnSegment(p, a, b);
18→  return distance(p, point);
19→}
20→
21→export function segmentLength(a, b) {
22→  return distance(a, b);
23→}
24→
25→export function segmentIntersection(a1, a2, b1, b2) {
26→  const d1 = subtract(a2, a1);
27→  const d2 = subtract(b2, b1);
28→  const cross = d1.x * d2.y - d1.y * d2.x;
29→  if (Math.abs(cross) < 1e-10) return null;
30→
31→  const d = subtract(b1, a1);
32→  const t = (d.x * d2.y - d.y * d2.x) / cross;
33→  const u = (d.x * d1.y - d.y * d1.x) / cross;
34→
35→  if (t >= 0 && t <= 1 && u >= 0 && u <= 1) {
36→    return add(a1, scale(d1, t));
37→  }
38→  return null;
39→}
40→

 1→import { subtract, normalize, perpendicular, scale, add, dot } from './point';
 2→import { segmentLength } from './line';
 3→
 4→export function wallOutline(wall) {
 5→  const dir = normalize(subtract(wall.end, wall.start));
 6→  const perp = perpendicular(dir);
 7→  const halfThick = wall.thickness / 2;
 8→  const offset = scale(perp, halfThick);
 9→
10→  return [
11→    add(wall.start, offset),
12→    add(wall.end, offset),
13→    subtract(wall.end, offset),
14→    subtract(wall.start, offset),
15→  ];
16→}
17→
18→export function wallLength(wall) {
19→  return segmentLength(wall.start, wall.end);
20→}
21→
22→export function positionOnWall(wall, offset) {
23→  const dir = normalize(subtract(wall.end, wall.start));
24→  return add(wall.start, scale(dir, offset));
25→}
26→
27→export function wallDirection(wall) {
28→  return normalize(subtract(wall.end, wall.start));
29→}
30→
31→export function wallAngle(wall) {
32→  const dx = wall.end.x - wall.start.x;
33→  const dy = wall.end.y - wall.start.y;
34→  return Math.atan2(dy, dx);
35→}
36→
37→export function projectPointOnWall(wall, point) {
38→  const dir = subtract(wall.end, wall.start);
39→  const len = segmentLength(wall.start, wall.end);
40→  if (len === 0) return 0;
41→  const toPoint = subtract(point, wall.start);
42→  const t = dot(toPoint, dir) / (len * len);
43→  return Math.max(0, Math.min(len, t * len));
44→}
45→
46→export function doorOutlineOnWall(wall, door) {
47→  const dir = wallDirection(wall);
48→  const perp = perpendicular(dir);
49→  const halfThick = wall.thickness / 2;
50→  const halfWidth = door.width / 2;
51→
52→  const center = positionOnWall(wall, door.offset);
53→  const start = add(center, scale(dir, -halfWidth));
54→  const end = add(center, scale(dir, halfWidth));
55→
56→  return {
57→    center,
58→    start,
59→    end,
60→    p1: add(start, scale(perp, halfThick)),
61→    p2: add(end, scale(perp, halfThick)),
62→    p3: subtract(end, scale(perp, halfThick)),
63→    p4: subtract(start, scale(perp, halfThick)),
64→    angle: wallAngle(wall),
65→    width: door.width,
66→    openDirection: door.openDirection,
67→  };
68→}
69→
70→export function windowOutlineOnWall(wall, window_) {
71→  const dir = wallDirection(wall);
72→  const perp = perpendicular(dir);
73→  const halfThick = wall.thickness / 2;
74→  const halfWidth = window_.width / 2;
75→
76→  const center = positionOnWall(wall, window_.offset);
