22→function overlapsExisting(wallId, offset, width, doors, windows) {
23→  const halfW = width / 2;
24→  const min = offset - halfW;
25→  const max = offset + halfW;
26→
27→  for (const d of doors) {
28→    if (d.wallId !== wallId) continue;
29→    const dMin = d.offset - d.width / 2;
30→    const dMax = d.offset + d.width / 2;
31→    if (min < dMax && max > dMin) return true;
32→  }
33→  for (const w of windows) {
34→    if (w.wallId !== wallId) continue;
35→    const wMin = w.offset - w.width / 2;
36→    const wMax = w.offset + w.width / 2;
37→    if (min < wMax && max > wMin) return true;
38→  }
39→  return false;
